  `created_by` int DEFAULT NULL,
  `modified_by` int DEFAULT NULL,
  `created_date` datetime DEFAULT CURRENT_TIMESTAMP,
  `modified_date` datetime DEFAULT CURRENT_TIMESTAMP,
  `is_active` tinyint DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `TS_USER_REQUESTS_USER_ID_MAIN_USERS_idx` (`user_id`),
  KEY `TS_USER_REQUESTS_WORK_MODE_ID_WORK_MODES_idx` (`work_mode_id`),
  CONSTRAINT `TS_USER_REQUESTS_USER_ID_MAIN_USERS` FOREIGN KEY (`user_id`) REFERENCES `main_users` (`id`),
